const webhookBinary = $('Webhook').item.binary;
if (webhookBinary && webhookBinary.image) {
  $input.first().binary = { imagen: webhookBinary.image };
}
return $input.all();

const rows = $input.all();
const historialOrdenado = [...rows].reverse();
const contexto = historialOrdenado
  .map(r => {
    const rol = r.json.rol === 'user' ? 'Usuario' : 'Asistente';
    return `${rol}: ${r.json.mensaje}`;
  })
  .join('\n');

const msgActual = $('guardar-msg').first().json.mensaje_final || '';

return [{
  json: {
    contexto_historial: contexto,
    mensaje_actual: msgActual
  }
}];

