// Detectar si el usuario pidió los pasos de una receta específica
const output = $('agente-recetas').item.json.output || '';
const mensajeUsuario = $('preparar-contexto').item.json.mensaje_actual || '';

// Buscar nombre de receta entre comillas (ej: Quiero hacer "Arroz con pollo")
// O extraerlo de frases como 'hacer X detallado', 'preparar X'
const matchComillas = mensajeUsuario.match(/["«“](.*?)["»”]/);
const matchHacer = mensajeUsuario.match(/(?:hacer|preparar|cocinar)\s+(?:la\s+|el\s+|los\s+|las\s+)?([\w\s]+?)(?:,|\.|$)/i);
const nombreReceta = matchComillas ? matchComillas[1].trim()
                   : matchHacer   ? matchHacer[1].trim()
                   : null;

// Buscar video si el usuario pide pasos/receta
const pidePasos = /pasos|preparar|hacer|cocinar|dame|cómo/i.test(mensajeUsuario) && nombreReceta;

return [{
  json: {
    output,
    nombre_receta: nombreReceta || '',
    buscar_video: !!pidePasos,
    imagen_url: null
  }
}];

// Extraer imagen base64 del output del nodo Gemini imagen
const item = $input.first();
let imagenUrl = null;

try {
  // El nodo googleGemini image devuelve el binario en item.binary
  const binary = item.binary;
  if (binary) {
    const key = Object.keys(binary)[0];
    if (key) {
      const b64 = binary[key].data;
      const mime = binary[key].mimeType || 'image/png';
      if (b64) imagenUrl = `data:${mime};base64,${b64}`;
    }
  }
} catch (e) {}

const det = $('detectar-receta').item.json;
const output = det.output || '';
const nombreReceta = det.nombre_receta || '';
return [{ json: { output, imagen_url: imagenUrl, nombre_receta: nombreReceta, buscar_video: true } }];

// Sin imagen: solo devolver el output del agente con nombre de receta
const output = $('detectar-receta').item.json.output || '';
const nombreReceta = $('detectar-receta').item.json.nombre_receta || '';
const generarImagen = $('detectar-receta').item.json.generar_imagen || false;
return [{ json: { output, imagen_url: null, nombre_receta: nombreReceta, buscar_video: generarImagen } }];

// Construir URL de búsqueda de YouTube sin necesidad de API key
const prev = $('detectar-receta').first().json;
const nombreReceta = prev.nombre_receta || '';

const query = encodeURIComponent('como preparar ' + nombreReceta + ' receta paso a paso');
const videoUrl = `https://www.youtube.com/results?search_query=${query}`;

// Thumbnail genérico de YouTube para búsquedas
const videoThumbnail = `https://img.youtube.com/vi/default/mqdefault.jpg`;

return [{ json: {
  output: prev.output,
  imagen_url: prev.imagen_url || null,
  video_url: videoUrl,
  video_titulo: `Ver videos: cómo preparar ${nombreReceta}`,
  video_thumbnail: null
}}];

// Sin video: pasar output limpio
const prev = $('detectar-receta').first().json;
return [{ json: {
  output: prev.output,
  imagen_url: prev.imagen_url || null,
  video_url: null,
  video_titulo: null,
  video_thumbnail: null
}}];
